"use client";

import { USER_COLORS } from "@/lib/types";

interface Stat {
  id: number;
  name: string;
  trip_count: number;
}

interface UsageStatsProps {
  stats: Stat[];
  year: number;
  availableYears: string[];
  onYearChange: (year: number) => void;
}

export default function UsageStats({ stats, year, availableYears, onYearChange }: UsageStatsProps) {
  const maxTrips = Math.max(...stats.map((s) => s.trip_count), 1);
  const totalTrips = stats.reduce((sum, s) => sum + s.trip_count, 0);

  return (
    <div className="bg-white rounded-xl border border-gray-200 p-4">
      <div className="flex items-center justify-between mb-3">
        <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-wide">
          Usage — {totalTrips} trips
        </h3>
        <div className="flex items-center gap-1.5">
          <button
            onClick={() => onYearChange(year - 1)}
            className="p-0.5 hover:bg-gray-100 rounded transition-colors text-gray-400"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          {availableYears.length > 2 ? (
            <select
              value={year}
              onChange={(e) => onYearChange(Number(e.target.value))}
              className="text-xs font-semibold text-gray-700 bg-transparent border-none cursor-pointer text-center focus:outline-none"
            >
              {availableYears.map((y) => (
                <option key={y} value={y}>{y}</option>
              ))}
            </select>
          ) : (
            <span className="text-xs font-semibold text-gray-700">{year}</span>
          )}
          <button
            onClick={() => onYearChange(year + 1)}
            className="p-0.5 hover:bg-gray-100 rounded transition-colors text-gray-400"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        </div>
      </div>

      <div className="space-y-1">
        {stats.map((stat) => (
          <div key={stat.id} className="flex items-center gap-2">
            <div
              className="w-5 h-5 rounded-full flex items-center justify-center text-white text-[8px] font-bold shrink-0"
              style={{ backgroundColor: USER_COLORS[stat.name] || "#6b7280" }}
            >
              {stat.name[0]}
            </div>
            <span className="text-[11px] text-gray-600 w-14 shrink-0 truncate">{stat.name}</span>
            <div className="flex-1 h-3 bg-gray-100 rounded-full overflow-hidden">
              <div
                className="h-full rounded-full transition-all duration-500"
                style={{
                  width: stat.trip_count > 0 ? `${Math.max((stat.trip_count / maxTrips) * 100, 8)}%` : "0%",
                  backgroundColor: USER_COLORS[stat.name] || "#6b7280",
                  opacity: stat.trip_count > 0 ? 1 : 0.15,
                }}
              />
            </div>
            <span className="text-[11px] font-medium text-gray-500 w-5 text-right">{stat.trip_count}</span>
          </div>
        ))}
      </div>

      {totalTrips === 0 && (
        <p className="text-center text-xs text-gray-400 py-3">No trips recorded for {year}</p>
      )}
    </div>
  );
}
