"use client";

import { useCallback, useRef, useMemo } from "react";
import { Reservation, User, USER_COLORS } from "@/lib/types";

interface CalendarProps {
  reservations: Reservation[];
  currentUser: User | null;
  onDayClick: (dateStr: string) => void;
  month: Date;
  onMonthChange: (date: Date) => void;
}

function getDaysInMonth(year: number, month: number): number {
  return new Date(year, month + 1, 0).getDate();
}

function getFirstDayOfMonth(year: number, month: number): number {
  const day = new Date(year, month, 1).getDay();
  return day === 0 ? 6 : day - 1;
}

function formatDate(year: number, month: number, day: number): string {
  return `${year}-${String(month + 1).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December",
];

const DAY_NAMES = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

export default function Calendar({
  reservations,
  currentUser,
  onDayClick,
  month,
  onMonthChange,
}: CalendarProps) {
  const touchStartX = useRef<number | null>(null);
  const touchStartY = useRef<number | null>(null);
  const year = month.getFullYear();
  const monthIndex = month.getMonth();
  const daysInMonth = getDaysInMonth(year, monthIndex);
  const firstDay = getFirstDayOfMonth(year, monthIndex);

  const today = new Date();
  const todayStr = formatDate(today.getFullYear(), today.getMonth(), today.getDate());
  const isCurrentMonth = year === today.getFullYear() && monthIndex === today.getMonth();

  const reservationMap = new Map<string, Reservation>();
  reservations.forEach((r) => reservationMap.set(r.date, r));

  const prevMonth = useCallback(() => {
    onMonthChange(new Date(year, monthIndex - 1, 1));
  }, [year, monthIndex, onMonthChange]);

  const nextMonth = useCallback(() => {
    onMonthChange(new Date(year, monthIndex + 1, 1));
  }, [year, monthIndex, onMonthChange]);

  const goToToday = useCallback(() => {
    onMonthChange(new Date());
  }, [onMonthChange]);

  const handleTouchStart = useCallback((e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
    touchStartY.current = e.touches[0].clientY;
  }, []);

  const handleTouchEnd = useCallback((e: React.TouchEvent) => {
    if (touchStartX.current === null || touchStartY.current === null) return;
    const dx = e.changedTouches[0].clientX - touchStartX.current;
    const dy = e.changedTouches[0].clientY - touchStartY.current;
    touchStartX.current = null;
    touchStartY.current = null;
    if (Math.abs(dx) > 60 && Math.abs(dx) > Math.abs(dy) * 1.5) {
      if (dx < 0) nextMonth();
      else prevMonth();
    }
  }, [nextMonth, prevMonth]);

  const days: Array<{ day: number | null; dateStr: string; dayOfWeek: number }> = [];
  for (let i = 0; i < firstDay; i++) {
    days.push({ day: null, dateStr: "", dayOfWeek: i });
  }
  for (let d = 1; d <= daysInMonth; d++) {
    const idx = (firstDay + d - 1) % 7;
    days.push({ day: d, dateStr: formatDate(year, monthIndex, d), dayOfWeek: idx });
  }

  // Upcoming reservations (next 3 from today)
  const upcoming = useMemo(() => {
    return reservations
      .filter((r) => r.date >= todayStr && !r.cancelled_at)
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(0, 3);
  }, [reservations, todayStr]);

  return (
    <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100">
        <button onClick={prevMonth} className="p-1.5 hover:bg-gray-100 rounded-lg transition-colors text-gray-500">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <div className="flex items-center gap-2">
          <h2 className="text-sm font-semibold text-gray-900">
            {MONTH_NAMES[monthIndex]} {year}
          </h2>
          {!isCurrentMonth && (
            <button
              onClick={goToToday}
              className="text-[10px] font-medium bg-gray-100 hover:bg-gray-200 text-gray-600 px-2 py-0.5 rounded transition-colors"
            >
              Today
            </button>
          )}
        </div>
        <button onClick={nextMonth} className="p-1.5 hover:bg-gray-100 rounded-lg transition-colors text-gray-500">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Day headers */}
      <div className="grid grid-cols-7 border-b border-gray-100">
        {DAY_NAMES.map((name, i) => (
          <div key={name} className={`text-center text-[10px] font-semibold uppercase tracking-wider py-2 ${
            i >= 5 ? "text-sky-500 bg-sky-50/40" : "text-gray-400"
          }`}>
            {name}
          </div>
        ))}
      </div>

      {/* Days grid */}
      <div
        className="grid grid-cols-7 gap-px bg-gray-100"
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
      >
        {days.map(({ day, dateStr, dayOfWeek }, i) => {
          const isWeekend = dayOfWeek >= 5;

          if (day === null) {
            return <div key={`empty-${i}`} className={`min-h-[2.75rem] sm:min-h-[3.25rem] ${isWeekend ? "bg-sky-50/30" : "bg-white"}`} />;
          }

          const reservation = reservationMap.get(dateStr);
          const isToday = dateStr === todayStr;
          const isPast = dateStr < todayStr;

          return (
            <button
              key={dateStr}
              onClick={() => currentUser && onDayClick(dateStr)}
              disabled={!currentUser}
              className={`
                relative min-h-[2.75rem] sm:min-h-[3.25rem] p-0.5 flex flex-col items-center transition-colors
                ${isWeekend ? "bg-sky-50/30" : "bg-white"}
                ${isPast && !reservation ? "opacity-35" : ""}
                ${currentUser ? "hover:bg-gray-50 active:bg-gray-100 cursor-pointer" : ""}
              `}
            >
              <span
                className={`text-[11px] font-medium w-5 h-5 flex items-center justify-center rounded-full ${
                  isToday
                    ? "bg-gray-900 text-white"
                    : isWeekend
                      ? "text-sky-700"
                      : "text-gray-700"
                }`}
              >
                {day}
              </span>

              {reservation && (
                <div
                  className="mt-0.5 w-full rounded px-0.5 py-px text-center"
                  style={{
                    backgroundColor: USER_COLORS[reservation.user_name || ""] + "18",
                    borderLeft: `2px solid ${USER_COLORS[reservation.user_name || ""] || "#6b7280"}`,
                  }}
                >
                  <span className="text-[9px] font-medium leading-tight block truncate" style={{
                    color: USER_COLORS[reservation.user_name || ""] || "#6b7280",
                  }}>
                    {reservation.user_name}
                  </span>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Upcoming reservations */}
      {upcoming.length > 0 && (
        <div className="px-4 py-3 border-t border-gray-100">
          <h4 className="text-[10px] font-semibold text-gray-400 uppercase tracking-wide mb-2">
            Coming up
          </h4>
          <div className="space-y-1.5">
            {upcoming.map((r) => {
              const [ry, rm, rd] = r.date.split("-").map(Number);
              const d = new Date(ry, rm - 1, rd);
              const friendly = d.toLocaleDateString("en-GB", { weekday: "short", day: "numeric", month: "short" });
              const isToday2 = r.date === todayStr;
              return (
                <button
                  key={r.id}
                  onClick={() => onDayClick(r.date)}
                  className="w-full flex items-center gap-2.5 py-1 px-1 rounded-md hover:bg-gray-50 transition-colors text-left"
                >
                  <div
                    className="w-2 h-2 rounded-full shrink-0"
                    style={{ backgroundColor: USER_COLORS[r.user_name || ""] || "#6b7280" }}
                  />
                  <span className="text-xs text-gray-700 flex-1">
                    <span className="font-medium">{r.user_name}</span>
                    <span className="text-gray-400 mx-1">—</span>
                    <span className={isToday2 ? "font-medium text-gray-900" : ""}>
                      {isToday2 ? "Today" : friendly}
                    </span>
                  </span>
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}
